import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"装甲格斗术","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/防御类/装甲格斗术.md","filePath":"4.资源分区/6.技艺及称号/防御类/装甲格斗术.md"}'),b={name:"4.资源分区/6.技艺及称号/防御类/装甲格斗术.md"};function o(d,e,_,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"装甲格斗术",tabindex:"-1"},[n("装甲格斗术 "),r("a",{class:"header-anchor",href:"#装甲格斗术","aria-label":'Permalink to "装甲格斗术"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调012")])])],-1),s('<h1 id="装甲格斗术-1" tabindex="-1">装甲格斗术 <a class="header-anchor" href="#装甲格斗术-1" aria-label="Permalink to &quot;装甲格斗术&quot;">​</a></h1><p>装甲格斗术</p><p>运用重甲的优势去抵挡敌人的致命攻击并非是过于高深的技巧，只是学费往往较为昂贵。这是主神从无数战场将士厮杀经验中总合而成的铠甲使用技巧。</p><p>前提：穿着重甲、盔甲防御为所有防御类型中的最高者。</p><p>D级<br> D+1000<br> 强化者的盔甲防御提升耐力附加点，承受的盔甲减值减少耐力附加点。<br> 若强化者的盔甲减值已抵消至0，则将后续获得的盔甲减值减少效果转化为三豁免检定上的增强加值，你至多转化耐力附加成功*2点豁免检定上的增强加值。</p><p>C级<br> C+2000<br> 强化者获得基于盔甲防御的【适应】。<br> 强化者的盔甲防御提升力量附加点，承受的盔甲减值减少力量附加点。<br> 强化者的盔甲防御抵消等同于【力量附加+耐力附加】点破甲。</p><p>牝鹿阔步<br> D+500<br> 盔甲构成了一道无法让人忽视的防线，这让所有试图绕开的敌人都束手无策。<br> 敌方单位在你的触及范围内时，其视为处于D级影响心灵来源的困难地形影响下。<br> 每轮一次，当敌方单位试图主动离开你的触及范围时，你可以反射动作对其进行一次冲撞，若对方失败则会倒地。<br> 差价升级：<br> C+1000: 敌方单位在你的触及范围内时，其视为处于C级影响心灵来源的困难地形影响下。<br> 每轮一次，当敌方单位试图主动离开你的触及范围时，你可以反射动作对其进行一次冲撞，若对方失败则会倒地，并在这一轮内移动速度减少20米。</p><p>犀牛坚毅<br> D+500<br> 强化者在受到强制性位移效果时，减少等同于【力量附加】*5米的位移距离。<br> 强化者在被动进行绊摔、冲撞检定对抗时，额外获得【耐力附加】*2点器械加值。<br> 差价升级至C+1000：强化者获得基于盔甲防御的【坚韧】</p><p>猛虎怒吼<br> C+1500<br> 当一个单位对你进行攻击后，若这次攻击造成的伤害值不高于你的力量属性值且你的盔甲防御未被破穿。你可以自由动作对其进行一次怒吼，令其受到1点不可豁免的音波严重伤害。<br> 若这次攻击未对你造成任何伤害，则你可以将【力量属性与耐力属性】上的附加成功加入该伤害。<br> 这一能力一轮内最多生效【耐力附加】次。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(b,[["render",o]]);export{f as __pageData,m as default};
